'use strict';

/**
* Subtract a scalar constant from each element in a strided array.
*
* @module @stdlib/blas-ext-base-gxsa
*
* @example
* import gxsa from '@stdlib/blas-ext-base-gxsa';
*
* var x = [ -2.0, 1.0, 3.0, -5.0, 4.0, 0.0, -1.0, -3.0 ];
*
* gxsa( x.length, 5.0, x, 1 );
* // x => [ -7.0, -4.0, -2.0, -10.0, -1.0, -5.0, -6.0, -8.0 ]
*
* @example
* import gxsa from '@stdlib/blas-ext-base-gxsa';
*
* var x = [ -2.0, 1.0, 3.0, -5.0, 4.0, 0.0, -1.0, -3.0 ];
*
* gxsa.ndarray( x.length, 5.0, x, 1, 0 );
* // x => [ -7.0, -4.0, -2.0, -10.0, -1.0, -5.0, -6.0, -8.0 ]
*/

// MODULES //

import setReadOnly from '@stdlib/utils-define-nonenumerable-read-only-property';
import main from './main.js';
import ndarray from './ndarray.js';


// MAIN //

setReadOnly( main, 'ndarray', ndarray );


// EXPORTS //

export default main;
